// TG-142: Scrape competitor websites + fetch previous snapshots for delta
const competitors = Array.isArray($input.first().json) ? $input.first().json : [];
if (competitors.length === 0) {
  return [{ json: { competitors: [], error: 'No active competitors found' } }];
}

const supabaseUrl = $vars.TG_SUPABASE_URL + '/rest/v1';
const supabaseKey = $vars.TG_SUPABASE_SERVICE_KEY;
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json'
};

const oneWeekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const results = [];

for (const comp of competitors) {
  const result = {
    id: comp.id,
    name: comp.name,
    domain: comp.domain,
    services: comp.services,
    location: comp.location,
    website_title: null,
    website_description: null,
    website_status: null,
    notable_changes: [],
    previous_snapshot: null,
    error: null
  };

  // 1. Scrape competitor website for meta info
  if (comp.domain) {
    try {
      const html = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://${comp.domain}`,
        options: { redirect: { follow: true }, timeout: 10000 }
      });
      result.website_status = 'up';
      // Extract title
      const titleMatch = typeof html === 'string' ? html.match(/<title[^>]*>([^<]+)<\/title>/i) : null;
      result.website_title = titleMatch ? titleMatch[1].trim() : null;
      // Extract meta description
      const descMatch = typeof html === 'string' ? html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']+)["']/i) : null;
      result.website_description = descMatch ? descMatch[1].trim() : null;
    } catch (e) {
      result.website_status = 'down_or_error';
      result.error = e.message || 'Failed to fetch website';
    }
  }

  // 2. Fetch previous snapshot for delta comparison
  try {
    const snapshots = await this.helpers.httpRequest({
      method: 'GET',
      url: `${supabaseUrl}/competitor_snapshots?competitor_id=eq.${comp.id}&order=snapshot_date.desc&limit=1`,
      headers: supabaseHeaders
    });
    if (Array.isArray(snapshots) && snapshots.length > 0) {
      result.previous_snapshot = snapshots[0];
    }
  } catch (e) { /* no previous data */ }

  results.push(result);
}

return [{ json: { competitors: results, snapshot_date: new Date().toISOString().split('T')[0] } }];

// TG-142: Detect changes and build alerts
const { competitors, snapshot_date } = $input.first().json;

const alerts = [];
const scored = [];

for (const comp of competitors) {
  const prev = comp.previous_snapshot;
  const changes = [];

  // Detect website title change (could indicate rebrand or new services)
  if (prev && prev.notable_changes) {
    try {
      const prevData = typeof prev.notable_changes === 'string' ? JSON.parse(prev.notable_changes) : prev.notable_changes;
      if (prevData.website_title && comp.website_title && prevData.website_title !== comp.website_title) {
        changes.push(`Title changed: "${prevData.website_title}" -> "${comp.website_title}"`);
        alerts.push(`${comp.name}: Website title changed! May indicate rebrand or new services.`);
      }
    } catch (e) { /* not JSON, skip */ }
  }

  // Detect website down
  if (comp.website_status === 'down_or_error') {
    changes.push('Website unreachable');
    alerts.push(`${comp.name}: Website is DOWN (${comp.error})`);
  }

  scored.push({
    id: comp.id,
    name: comp.name,
    domain: comp.domain,
    website_status: comp.website_status,
    website_title: comp.website_title,
    website_description: comp.website_description,
    changes,
    review_count: prev ? prev.review_count : null,
    rating: prev ? prev.rating : null,
    new_reviews_since_last: 0
  });
}

return [{ json: { competitors: scored, alerts, snapshot_date } }];

// TG-142: Store competitor snapshots in Supabase
const { competitors, snapshot_date } = $input.first().json;

const supabaseUrl = $vars.TG_SUPABASE_URL + '/rest/v1';
const supabaseKey = $vars.TG_SUPABASE_SERVICE_KEY;
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

let stored = 0;
let failed = 0;

for (const comp of competitors) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${supabaseUrl}/competitor_snapshots`,
      headers: supabaseHeaders,
      body: {
        competitor_id: comp.id,
        rating: comp.rating,
        review_count: comp.review_count,
        new_reviews_since_last: comp.new_reviews_since_last || 0,
        notable_changes: JSON.stringify({
          website_title: comp.website_title,
          website_description: comp.website_description,
          website_status: comp.website_status,
          changes: comp.changes
        }),
        snapshot_date
      }
    });
    stored++;
  } catch (e) {
    failed++;
  }
}

return [{ json: { ...$input.first().json, stored, failed } }];

