={{ (function() {
  const d = $json;
  const lines = [
    '\ud83d\udd0d COMPETITOR MONITOR',
    `Week of ${d.snapshot_date}`,
    `Tracked: ${d.competitors.length} competitors`,
    `Snapshots stored: ${d.stored}/${d.competitors.length}`,
    ''
  ];
  for (const c of d.competitors) {
    const status = c.website_status === 'up' ? '\u2705' : '\u274c';
    lines.push(`${status} ${c.name} (${c.domain || 'no domain'})`);
    if (c.website_title) lines.push(`   Title: ${c.website_title.substring(0, 60)}`);
    if (c.changes && c.changes.length > 0) {
      for (const ch of c.changes) lines.push(`   \u26a0\ufe0f ${ch}`);
    }
  }
  if (d.alerts && d.alerts.length > 0) {
    lines.push('');
    lines.push('\ud83d\udea8 ALERTS:');
    for (const a of d.alerts) lines.push(`- ${a}`);
  }
  return lines.join('\n');
})() }}
